class Solution {
public:
    int numberOfArrays(string s, int k) {
        int n = s.size();
        const int MOD = 1e9 + 7;
        vector<int> dp(n + 1, 0);
        dp[n] = 1;
        for (int i = n - 1; i >= 0; --i) {
            if (s[i] == '0') continue;
            long long num = 0;
            for (int j = i; j < n; ++j) {
                num = num * 10 + (s[j] - '0');
                if (num > k) break;
                dp[i] = (dp[i] + dp[j + 1]) % MOD;
            }
        }
        return dp[0];
    }
};
efficiency: HIGH
time complexity: O(n log k)
space complexity: O(n)
energy implications: LOW
explanation: Dynamic programming is used to track the number of valid arrays ending at each position. The solution iterates through the string from right to left, considering all possible numbers that can be formed without exceeding k, and sums up the possibilities. The use of modulo operation prevents overflow. 
